/**
 * Modular exponentiation: (base^exp) % mod
 */
function power(base, exp) {
    let res = 1n;
    base = BigInt(base) % BigInt(MOD);
    exp = BigInt(exp);
    const m = BigInt(MOD);

    while (exp > 0n) {
        if (exp % 2n === 1n) res = (res * base) % m;
        base = (base * base) % m;
        exp /= 2n;
    }
    return Number(res);
}

/**
 * Modular inverse using Fermat's Little Theorem
