// Global cache for factorials up to 10^5
let factCache = [];

function precomputeFactorials(maxN) {
    if (maxN < 0) return;
    factCache = new Array(maxN + 1);
    factCache[0] = 1;
    for (let i = 1; i <= maxN; i++) {
        factCache[i] = (BigInt(factCache[i - 1]) * BigInt(i)) % BigInt(MOD);
    }
