function combinations(n, k) {
    if (k < 0 || k > n) {
        return 0;
    }

    // Ensure factorials are precomputed up to n
    if (factCache.length <= n) {
        precomputeFactorials(n);
    }

    // nCk = n! / (k! * (n-k)!)
    let numerator = factCache[n];
    let denominator = (BigInt(factCache[k]) * BigInt(factCache[n - k])) % BigInt(MOD);

    let inv_denominator = modInverse(Number(denominator));

    return (BigInt(numerator) * BigInt(inv_denominator)) % BigInt(MOD);
}


function solve(n, pos, k) {
    // We need to calculate 2 * C(N-1, K) mod MOD

    const N_prime = n - 1;

    if (N_prime < 0) {
